-- Composite index for analytics queries (date + query)
CREATE INDEX IF NOT EXISTS idx_search_analytics_date_query 
  ON search_analytics(createdAt, query);

-- Index for ICD description search
CREATE INDEX IF NOT EXISTS idx_icd_codes_description 
  ON icd_codes(description(100));

-- Composite index for drug entry search (scientific + indication)
CREATE INDEX IF NOT EXISTS idx_drug_entries_sci_indication 
  ON drug_entries(scientific_name, indication);

